// ==UserScript==
// @name         ClipFetch Cookie Sync
// @namespace    https://clipfetch.app
// @version      1.0
// @description  Automatically sends fresh YouTube cookies to your ClipFetch server
// @author       ClipFetch
// @match        https://www.youtube.com/*
// @grant        none
// ==/UserScript==

(function () {
  'use strict';

  const SERVER_URL = localStorage.getItem('clipfetch_server') || window.location.origin;

  function getNetscapeCookies() {
    const cookies = document.cookie.split(';');
    const lines = [
      '# Netscape HTTP Cookie File',
      '# Auto-generated by ClipFetch Cookie Sync',
      '',
    ];
    const domain = '.youtube.com';
    cookies.forEach((c) => {
      const [name, ...rest] = c.trim().split('=');
      if (!name) return;
      const value = rest.join('=');
      const expiry = Math.floor(Date.now() / 1000) + 86400 * 365;
      lines.push(`${domain}\tTRUE\t/\tTRUE\t${expiry}\t${name}\t${value}`);
    });
    return lines.join('\n');
  }

  function syncCookies() {
    const cookies = getNetscapeCookies();
    fetch(SERVER_URL + '/api/cookies', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ cookies }),
    }).then((r) => {
      if (r.ok) console.log('[ClipFetch] Cookies synced');
    }).catch(() => {});
  }

  const existing = document.getElementById('clipfetch-sync');
  if (!existing) {
    const btn = document.createElement('button');
    btn.id = 'clipfetch-sync';
    btn.textContent = 'Sync YouTube Cookies to ClipFetch';
    btn.style.cssText =
      'position:fixed;bottom:16px;right:16px;z-index:9999;background:#2563eb;color:#fff;border:none;border-radius:8px;padding:8px 14px;font-size:13px;cursor:pointer;box-shadow:0 2px 8px rgba(0,0,0,.2)';
    btn.onclick = () => {
      syncCookies();
      btn.textContent = '✓ Synced!';
      setTimeout(() => (btn.textContent = 'Sync YouTube Cookies to ClipFetch'), 3000);
    };
    document.body.appendChild(btn);
  }

  syncCookies();
})();
